    if (uc_op_r37) regs[37] <= s_fadd_9eba50d4_0_y0;
    if (uc_op_r38) regs[38] <= s_fmul_68b24f7b_0_y0;
    if (uc_op_r39) regs[39] <= s_fadd_9eba50d4_0_y0;

    // Control and persistent state: the reset-gated registers.
    if (rst) begin
        pc            <= 0;
        err_pc_q      <= 0;
        transacting_q <= 0;
        regs[3] <= 44'h00000000000;  // x_0 reset snapshot
        regs[4] <= 44'h00000000000;  // x_1 reset snapshot
        regs[5] <= 44'h00000000000;  // x_2 reset snapshot
        regs[6] <= 44'h3f800000000;  // P_urt_0 reset snapshot
        regs[7] <= 44'h00000000000;  // P_urt_1 reset snapshot
        regs[8] <= 44'h00000000000;  // P_urt_2 reset snapshot
        regs[9] <= 44'h3f800000000;  // P_urt_3 reset snapshot
        regs[10] <= 44'h00000000000;  // P_urt_4 reset snapshot
        regs[11] <= 44'h3f800000000;  // P_urt_5 reset snapshot
    end else begin
        pc <= next_pc;
        transacting_q <= (transacting_q << 1) | transacting_in;
        if (err) err_pc_q <= pc - FETCH_LAG;  // err wins; execution lags the fetch PC by FETCH_LAG, so step is pc-lag
        else if (in_ready && in_valid) err_pc_q <= 0;  // clear the diagnostic when a new transaction is accepted
        if (uc_op_r3) regs[3] <= s_fmul_68b24f7b_0_y0;
        if (uc_op_r4) regs[4] <= s_fmul_68b24f7b_0_y0;
        if (uc_op_r5) regs[5] <= s_fmul_68b24f7b_0_y0;
        case (uc_op_r6)
            2'd1: regs[6] <= s_fmul_68b24f7b_0_y0;
            2'd2: regs[6] <= s_fadd_9eba50d4_0_y0;
        endcase
        case (uc_op_r7)
            2'd1: regs[7] <= s_fadd_9eba50d4_0_y0;
            2'd2: regs[7] <= s_fmul_68b24f7b_0_y0;
        endcase
        if (uc_op_r8) regs[8] <= s_fmul_68b24f7b_0_y0;
        if (uc_op_r9) regs[9] <= s_fmul_68b24f7b_0_y0;
        if (uc_op_r10) regs[10] <= s_fmul_68b24f7b_0_y0;
        case (uc_op_r11)
            2'd1: regs[11] <= s_fmul_68b24f7b_0_y0;
            2'd2: regs[11] <= s_fdiv_56ea25b7_0_y0;
            2'd3: regs[11] <= s_fadd_9eba50d4_0_y0;
        endcase
    end
end

assign in_ready  = (pc == 0);
assign out_valid = (pc == LASTPC);  // result valid on PRESENT; execution lags the fetch by FETCH_LAG
assign err_pc    = err_pc_q;
assign state_x_0 = regs[3];
assign state_x_1 = regs[4];
assign state_x_2 = regs[5];
assign state_P_urt_0 = regs[6];
assign state_P_urt_1 = regs[7];
assign state_P_urt_2 = regs[8];
assign state_P_urt_3 = regs[9];
assign state_P_urt_4 = regs[10];
assign state_P_urt_5 = regs[11];

endmodule
